<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Ubuntu Desktop</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }

  body {
    overflow: hidden;
    font-family: 'Ubuntu', 'Segoe UI', Arial, sans-serif;
    background: #1a1a2e;
    color: #fff;
    user-select: none;
  }

  /* Desktop wallpaper area */
  #desktop {
    width: 100vw;
    height: 100vh;
    position: relative;
    background: linear-gradient(135deg, #0d47a1 0%, #1565c0 25%, #1976d2 50%, #0d47a1 75%, #0a3d8f 100%);
    background-size: cover;
    overflow: hidden;
  }

  /* Desktop wallpaper pattern overlay */
  #desktop::before {
    content: '';
    position: absolute;
    top: 0; left: 0; right: 0; bottom: 0;
    background-image:
      radial-gradient(circle at 20% 30%, rgba(255,255,255,0.06) 0%, transparent 50%),
      radial-gradient(circle at 80% 70%, rgba(255,255,255,0.04) 0%, transparent 50%),
      radial-gradient(circle at 50% 50%, rgba(255,255,255,0.03) 0%, transparent 60%);
    pointer-events: none;
    z-index: 0;
  }

  /* Taskbar */
  #taskbar {
    position: absolute;
    bottom: 0;
    left: 0;
    right: 0;
    height: 48px;
    background: rgba(26, 26, 50, 0.95);
    backdrop-filter: blur(12px);
    display: flex;
    align-items: center;
    padding: 0 12px;
    z-index: 1000;
    border-top: 1px solid rgba(255,255,255,0.1);
  }

  #taskbar .launcher {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 6px 14px;
    border-radius: 8px;
    cursor: pointer;
    transition: background 0.2s, transform 0.15s;
    font-size: 13px;
    color: #e0e0e0;
    white-space: nowrap;
  }

  #taskbar .launcher:hover {
    background: rgba(255,255,255,0.1);
    transform: scale(1.03);
  }

  #taskbar .launcher.active {
    background: rgba(255,255,255,0.15);
    border-bottom: 2px solid #4fc3f7;
  }

  #taskbar .launcher-icon {
    width: 22px;
    height: 22px;
    border-radius: 4px;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 16px;
  }

  /* Window */
  .window {
    position: absolute;
    background: #2d2d3f;
    border-radius: 8px;
    box-shadow: 0 8px 32px rgba(0,0,0,0.4), 0 2px 8px rgba(0,0,0,0.3);
    display: none;
    flex-direction: column;
    overflow: hidden;
    min-width: 360px;
    min-height: 240px;
    border: 1px solid rgba(255,255,255,0.08);
  }

  .window.visible { display: flex; }

  /* Window title bar */
  .win-titlebar {
    height: 36px;
    background: #1e1e2e;
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 12px;
    cursor: default;
    -webkit-app-region: drag;
    user-select: none;
  }

  .win-title {
    font-size: 13px;
    color: #b0b0c0;
    flex: 1;
    text-align: center;
    pointer-events: none;
  }

  .win-controls {
    display: flex;
    gap: 8px;
    -webkit-app-region: no-drag;
  }

  .win-close {
    width: 28px;
    height: 28px;
    border-radius: 50%;
    background: transparent;
    border: none;
    color: #a0a0b0;
    font-size: 14px;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: all 0.2s;
  }

  .win-close:hover {
    background: #e53935;
    color: white;
  }

  /* Window content */
  .win-body {
    flex: 1;
    overflow: auto;
    padding: 0;
  }

  /* Files app styles */
  #files-window .win-titlebar .win-title { font-weight: 500; color: #c8d6e5; }

  .file-toolbar {
    display: flex;
    align-items: center;
    gap: 12px;
    padding: 10px 14px;
    background: #1e1e2e;
    border-bottom: 1px solid rgba(255,255,255,0.06);
  }

  .file-toolbar button {
    padding: 4px 10px;
    border-radius: 4px;
    border: none;
    background: transparent;
    color: #b0b0c0;
    font-size: 12px;
    cursor: pointer;
    transition: all 0.15s;
  }

  .file-toolbar button:hover {
    background: rgba(255,255,255,0.1);
    color: #fff;
  }

  #files-path {
    font-size: 13px;
    color: #8ab4f8;
    min-width: 160px;
    flex-shrink: 0;
  }

  .file-list {
    padding: 8px 12px;
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(90px, 1fr));
    gap: 4px;
    max-height: calc(100vh - 160px);
    overflow-y: auto;
  }

  .fs-item {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 12px;
    border-radius: 6px;
    cursor: pointer;
    font-size: 13px;
    color: #c0c0d0;
    transition: background 0.15s, transform 0.1s;
    text-align: center;
    min-height: 48px;
    justify-content: center;
  }

  .fs-item:hover {
    background: rgba(255,255,255,0.06);
    transform: scale(1.02);
  }

  .fs-item:active {
    transform: scale(0.98);
  }

  .fs-icon { font-size: 24px; line-height: 1; }

  /* Notepad styles */
  #notepad-window .win-titlebar .win-title { color: #c8d6e5; }

  .tab-strip {
    display: flex;
    background: #1e1e2e;
    border-bottom: 1px solid rgba(255,255,255,0.06);
    overflow-x: auto;
    -webkit-app-region: no-drag;
  }

  .tab {
    padding: 8px 16px;
    font-size: 13px;
    color: #7a7a90;
    cursor: pointer;
    border-right: 1px solid rgba(255,255,255,0.04);
    background: transparent;
    white-space: nowrap;
    transition: all 0.15s;
    display: flex;
    align-items: center;
    gap: 6px;
    min-width: 80px;
    max-width: 200px;
  }

  .tab:hover { background: rgba(255,255,255,0.04); color: #b0b0c0; }

  .tab.active {
    background: #2d2d3f;
    color: #e0e0f0;
    border-bottom: 2px solid #4fc3f7;
  }

  .tab-close-btn {
    width: 16px;
    height: 16px;
    border-radius: 50%;
    background: transparent;
    border: none;
    color: #5a5a70;
    font-size: 10px;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    line-height: 1;
    opacity: 0;
    transition: all 0.15s;
  }

  .tab:hover .tab-close-btn { opacity: 1; }
  .tab-close-btn:hover { background: #e53935; color: white; }

  #new-tab {
    padding: 8px 12px;
    font-size: 12px;
    color: #7a7a90;
    cursor: pointer;
    border-left: 1px solid rgba(255,255,255,0.04);
    background: transparent;
    white-space: nowrap;
    transition: all 0.15s;
    display: flex;
    align-items: center;
    gap: 6px;
    -webkit-app-region: no-drag;
  }

  #new-tab:hover { background: rgba(255,255,255,0.04); color: #b0b0c0; }

  #editor {
    flex: 1;
    width: 100%;
    height: calc(100% - 60px);
    background: #1e1e2e;
    border: none;
    color: #d0d0e8;
    padding: 14px;
    font-family: 'Ubuntu Mono', 'Courier New', monospace;
    font-size: 13px;
    line-height: 1.6;
    resize: none;
    outline: none;
  }

  /* Scrollbar styling */
  ::-webkit-scrollbar { width: 8px; height: 8px; }
  ::-webkit-scrollbar-track { background: transparent; }
  ::-webkit-scrollbar-thumb { background: #4a4a60; border-radius: 4px; }
  ::-webkit-scrollbar-thumb:hover { background: #5a5a70; }

  /* Animations */
  @keyframes fadeIn { from { opacity: 0; transform: scale(0.95); } to { opacity: 1; transform: scale(1); } }
  .window.visible { animation: fadeIn 0.2s ease-out; }

  /* Responsive adjustments */
  @media (max-width: 600px) {
    #taskbar { padding: 0 8px; }
    .file-list { grid-template-columns: repeat(auto-fill, minmax(75px, 1fr)); gap: 3px; }
    .fs-item { font-size: 12px; padding: 6px 10px; }
  }
</style>
</head>
<body>

<div id="desktop">
  <!-- Taskbar -->
  <div id="taskbar">
    <div class="launcher" id="open-files" data-window="#files-window">
      <span class="launcher-icon">📁</span>
      <span>Files</span>
    </div>
    <div class="launcher" id="open-notepad" data-window="#notepad-window">
      <span class="launcher-icon">📝</span>
      <span>Notepad</span>
    </div>
  </div>

  <!-- Files Window -->
  <div id="files-window" class="window" style="top: 50px; left: 50px; width: 620px; height: 480px;">
    <div class="win-titlebar">
      <span class="win-title">Files</span>
      <button class="win-close" data-window="#files-window">×</button>
    </div>
    <div class="win-body">
      <div class="file-toolbar">
        <button id="files-up">↑ Parent</button>
        <span id="files-path">/</span>
      </div>
      <div class="file-list" id="file-list"></div>
    </div>
  </div>

  <!-- Notepad Window -->
  <div id="notepad-window" class="window" style="top: 50px; left: 700px; width: 680px; height: 480px;">
    <div class="win-titlebar">
      <span class="win-title">Notepad</span>
      <button class="win-close" data-window="#notepad-window">×</button>
    </div>
    <div class="win-body">
      <div class="tab-strip" id="tabs"></div>
      <button id="new-tab">+ New Tab</button>
      <textarea id="editor" placeholder="Start typing..."></textarea>
    </div>
  </div>
</div>

<script>
(function() {
  'use strict';

  // ========================
  // FILESYSTEM DATA (static fake)
  // ========================
  const FS = {
    '/': [
      { name: 'bin', type: 'dir' },
      { name: 'etc', type: 'dir' },
      { name: 'home', type: 'dir' },
      { name: 'usr', type: 'dir' },
      { name: 'var', type: 'dir' },
    ],
    '/bin': [
      { name: 'bash', type: 'file' },
      { name: 'ls', type: 'file' },
      { name: 'cp', type: 'file' },
      { name: 'mv', type: 'file' },
      { name: 'rm', type: 'file' },
    ],
    '/etc': [
      { name: 'passwd', type: 'file' },
      { name: 'hosts', type: 'file' },
      { name: 'ssh_config', type: 'file' },
    ],
    '/home': [
      { name: 'user', type: 'dir' },
    ],
    '/home/user': [
      { name: 'Documents', type: 'dir' },
      { name: 'Downloads', type: 'dir' },
      { name: 'Pictures', type: 'dir' },
      { name: 'readme.txt', type: 'file' },
    ],
    '/home/user/Documents': [
      { name: 'notes.md', type: 'file' },
      { name: 'todo.txt', type: 'file' },
    ],
    '/home/user/Downloads': [
      { name: 'setup.sh', type: 'file' },
      { name: 'image.png', type: 'file' },
    ],
    '/home/user/Pictures': [
      { name: 'screenshot.jpg', type: 'file' },
    ],
    '/usr': [
      { name: 'bin', type: 'dir' },
      { name: 'lib', type: 'dir' },
      { name: 'share', type: 'dir' },
    ],
    '/usr/bin': [
      { name: 'python3', type: 'file' },
      { name: 'node', type: 'file' },
      { name: 'git', type: 'file' },
    ],
    '/usr/lib': [
      { name: 'libc.so', type: 'file' },
    ],
    '/usr/share': [
      { name: 'man', type: 'dir' },
      { name: 'icons', type: 'dir' },
    ],
    '/var': [
      { name: 'log', type: 'dir' },
      { name: 'cache', type: 'dir' },
    ],
    '/var/log': [
      { name: 'syslog', type: 'file' },
      { name: 'auth.log', type: 'file' },
    ],
    '/var/cache': [
      { name: 'apt', type: 'dir' },
    ],
  };

  // ========================
  // WINDOW MANAGEMENT
  // ========================
  const windows = {};

  function openWindow(id) {
    if (!windows[id]) return;
    const win = document.querySelector(id);
    if (win.style.display === 'none' || !win.classList.contains('visible')) {
      win.classList.add('visible');
      // Bring to front
      bringToFront(win);
    }
  }

  function closeWindow(id) {
    const win = document.querySelector(id);
    if (!win) return;
    win.classList.remove('visible');
    windows[id] = false;
  }

  function bringToFront(el) {
    document.querySelectorAll('.window.visible').forEach(w => w.style.zIndex = '100');
    el.style.zIndex = '200';
  }

  // ========================
  // FILES APP
  // ========================
  let currentPath = '/';
  const fileListEl = document.getElementById('file-list');
  const filesPathEl = document.getElementById('files-path');
  const filesUpBtn = document.getElementById('files-up');

  function getEntries(path) {
    return FS[path] || [];
  }

  function renderFiles() {
    const entries = getEntries(currentPath);
    fileListEl.innerHTML = '';
    entries.forEach(entry => {
      const item = document.createElement('div');
      item.className = 'fs-item';
      if (entry.type === 'dir') {
        item.innerHTML = '<span class="fs-icon">📁</span><span>' + entry.name + '</span>';
      } else {
        item.innerHTML = '<span class="fs-icon">📄</span><span>' + entry.name + '</span>';
      }

      if (entry.type === 'dir') {
        // Double-click to navigate into folder
        item.addEventListener('dblclick', () => {
          const newPath = currentPath === '/' ? '/home/user/' + entry.name : currentPath + '/' + entry.name;
          navigateTo(newPath);
        });
      } else {
        // Single-click on files just shows a tooltip (no navigation)
        item.title = 'Click to open file';
      }

      fileListEl.appendChild(item);
    });
  }

  function navigateTo(path) {
    if (!FS[path]) return;
    currentPath = path;
    filesPathEl.textContent = path;
    renderFiles();
  }

  filesUpBtn.addEventListener('click', () => {
    const parts = currentPath.split('/').filter(Boolean);
    if (parts.length <= 1) return; // Can't go above root
    parts.pop();
    navigateTo(parts.join('/') || '/');
  });

  // Initial render
  renderFiles();

  // ========================
  // NOTEPAD APP
  // ========================
  const tabsEl = document.getElementById('tabs');
  const editorEl = document.getElementById('editor');
  const newTabBtn = document.getElementById('new-tab');
  let activeTabIndex = -1;
  let tabIdCounter = 0;

  function loadTabsFromStorage() {
    try {
      const data = JSON.parse(localStorage.getItem('notepad_tabs'));
      if (data && Array.isArray(data) && data.length > 0) {
        return data;
      }
    } catch(e) {}
    return [];
  }

  function saveTabsToStorage() {
    try {
      localStorage.setItem('notepad_tabs', JSON.stringify(getAllTabData()));
    } catch(e) {}
  }

  function getAllTabData() {
    const tabs = document.querySelectorAll('.tab');
    return Array.from(tabs).map(tab => ({
      id: tab.dataset.id,
      title: tab.textContent.trim(),
      content: editorEl.value
    }));
  }

  function createTab(title, content) {
    tabIdCounter++;
    const id = 'tab-' + tabIdCounter;
    const tab = document.createElement('div');
    tab.className = 'tab';
    tab.dataset.id = id;
    tab.innerHTML = '<span>' + title + '</span><button class="tab-close-btn" data-tab-id="' + id + '">✕</button>';

    // Click to switch
    tab.addEventListener('click', (e) => {
      if (e.target.classList.contains('tab-close-btn')) return;
      activateTab(id);
    });

    // Close button
    const closeBtn = tab.querySelector('.tab-close-btn');
    closeBtn.addEventListener('click', () => removeTab(id));

    tabsEl.appendChild(tab);
    return id;
  }

  function activateTab(id) {
    document.querySelectorAll('.tab').forEach(t => t.classList.remove('active'));
    const target = document.querySelector('.tab[data-id="' + id + '"]');
    if (target) {
      target.classList.add('active');
      editorEl.value = getTabContent(id);
      activeTabIndex = Array.from(document.querySelectorAll('.tab')).indexOf(target);
    }
  }

  function removeTab(id) {
    const tab = document.querySelector('.tab[data-id="' + id + '"]');
    if (!tab) return;

    // If removing the last tab, keep one empty
    const remaining = tabsEl.querySelectorAll('.tab').length - 1;
    if (remaining === 0) {
      createTab('Untitled', '');
      activateTab('tab-' + tabIdCounter);
      return;
    }

    // If removing active tab, switch to another
    if (id === getActiveTabId()) {
      const others = Array.from(tabsEl.querySelectorAll('.tab')).filter(t => t.dataset.id !== id);
      activateTab(others[0].dataset.id);
    }

    tab.remove();
  }

  function getActiveTabId() {
    return document.querySelector('.tab.active') ? document.querySelector('.tab.active').dataset.id : null;
  }

  function getTabContent(id) {
    const tabs = getAllTabData();
    return tabs.find(t => t.id === id)?.content || '';
  }

  function setTabContent(id, content) {
    const tabs = getAllTabData();
    const idx = tabs.findIndex(t => t.id === id);
    if (idx >= 0) {
      tabs[idx].content = content;
      saveTabsToStorage();
    }
  }

  function getTabTitle(id) {
    const tabs = getAllTabData();
    return tabs.find(t => t.id === id)?.title || 'Untitled';
  }

  // Restore tabs on load
  function restoreTabs() {
    const saved = loadTabsFromStorage();
    if (saved.length > 0) {
      saved.forEach(data => createTab(data.title, data.content));
      activateTab(saved[0].id);
    } else {
      createTab('Untitled', '');
    }
  }

  // New tab button
  newTabBtn.addEventListener('click', () => {
    const id = createTab('Untitled', '');
    activateTab(id);
  });

  // Editor input saves to storage
  editorEl.addEventListener('input', () => {
    if (getActiveTabId()) {
      setTabContent(getActiveTabId(), editorEl.value);
    }
  });

  restoreTabs();

  // ========================
  // LAUNCHER HANDLERS
  // ========================
  document.getElementById('open-files').addEventListener('click', () => openWindow('#files-window'));
  document.getElementById('open-notepad').addEventListener('click', () => openWindow('#notepad-window'));

  // Close buttons
  document.addEventListener('click', (e) => {
    if (e.target.classList.contains('win-close')) {
      const winId = e.target.dataset.window;
      closeWindow(winId);
    }
    if (e.target.classList.contains('tab-close-btn')) {
      const tabId = e.target.dataset.tabId;
      removeTab(tabId);
    }
  });

  // ========================
  // DRAGGABLE WINDOWS
  // ========================
  document.querySelectorAll('.win-titlebar').forEach(titlebar => {
    let isDragging = false;
    let startX, startY, startLeft, startTop;

    titlebar.addEventListener('mousedown', (e) => {
      if (e.target.classList.contains('win-close')) return;
      bringToFront(titlebar.parentElement);
      isDragging = true;
      startX = e.clientX;
      startY = e.clientY;
      const win = titlebar.parentElement;
      startLeft = win.offsetLeft;
      startTop = win.offsetTop;

      document.addEventListener('mousemove', onDrag);
      document.addEventListener('mouseup', stopDrag);
    });

    function onDrag(e) {
      if (!isDragging) return;
      const dx = e.clientX - startX;
      const dy = e.clientY - startY;
      win.style.left = (startLeft + dx) + 'px';
      win.style.top = (startTop + dy) + 'px';
    }

    function stopDrag() {
      isDragging = false;
      document.removeEventListener('mousemove', onDrag);
      document.removeEventListener('mouseup', stopDrag);
    }
  });

})();
</script>
</body>
</html>
